        if ' and ' in categories_part:
            categories_part = categories_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in categories_part.split(',')]
    elif 'including' in desc:
        categories_part = desc.split('including')[1].strip(' .')
        # Clean up the categories part
        if ' and ' in categories_part:
            categories_part = categories_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in categories_part.split(',')]
